<?php
namespace App\Controllers;
use App\Core\Controller;use App\Config\Database;use App\Helpers\{Auth,Csrf,Flash};
final class AccountController extends Controller {public function index():void{Auth::requireLogin();$db=Database::connection();$id=Auth::id();$q=$db->prepare("SELECT c.*,COALESCE(a.nombre,b.nombre) artista FROM favoritos f JOIN canciones c ON c.id=f.cancion_id LEFT JOIN artistas a ON a.id=c.artista_id LEFT JOIN bandas b ON b.id=c.banda_id WHERE f.usuario_id=?");$q->execute([$id]);$favorites=$q->fetchAll();$q=$db->prepare("SELECT * FROM listas WHERE usuario_id=? ORDER BY id DESC");$q->execute([$id]);$lists=$q->fetchAll();$q=$db->prepare("SELECT co.*,DATE_FORMAT(co.fecha_hora,'%d/%m/%Y %H:%i') fecha FROM compras co WHERE usuario_id=? ORDER BY id DESC");$q->execute([$id]);$purchases=$q->fetchAll();$plans=$db->query("SELECT * FROM planes WHERE estado=1")->fetchAll();$events=$db->query("SELECT * FROM eventos WHERE estado=1 AND fecha>=CURDATE() ORDER BY fecha")->fetchAll();$songs=$db->query("SELECT id,nombre FROM canciones WHERE estado=1 ORDER BY nombre")->fetchAll();$this->view('account/index',compact('favorites','lists','purchases','plans','events','songs'));} public function createList():void{Auth::requireLogin();Csrf::verify();$s=Database::connection()->prepare("INSERT INTO listas(usuario_id,nombre,descripcion) VALUES(?,?,?)");$s->execute([Auth::id(),trim($_POST['nombre']),trim($_POST['descripcion']??'')]);Flash::set('success','Lista creada.');Auth::go('/mi-cuenta');} public function addSong():void{Auth::requireLogin();Csrf::verify();Database::connection()->prepare("INSERT IGNORE INTO lista_canciones(lista_id,cancion_id) SELECT ?,? FROM listas WHERE id=? AND usuario_id=?")->execute([(int)$_POST['lista_id'],(int)$_POST['cancion_id'],(int)$_POST['lista_id'],Auth::id()]);Flash::set('success','Canción agregada a la lista.');Auth::go('/mi-cuenta');} public function buyPlan(int $id):void{Auth::requireLogin();Csrf::verify();$db=Database::connection();$s=$db->prepare("SELECT * FROM planes WHERE id=? AND estado=1");$s->execute([$id]);$p=$s->fetch();if(!$p)throw new \RuntimeException('Plan no disponible');$db->beginTransaction();$start=date('Y-m-d');$end=date('Y-m-d',strtotime('+'.(int)$p['duracion_dias'].' days'));$db->prepare("INSERT INTO membresias(usuario_id,plan_id,fecha_inicio,fecha_fin) VALUES(?,?,?,?)")->execute([Auth::id(),$id,$start,$end]);$subtotal=(float)$p['precio'];$tax=round($subtotal*.07,2);$sig=hash_hmac('sha256',Auth::id().'|'.$id.'|'.microtime(true),'RokolaRitmoPTY');$db->prepare("INSERT INTO compras(usuario_id,tipo,referencia_id,subtotal,itbms,total,metodo_pago,firma_digital) VALUES(?,'membresia',?,?,?,?,?,?)")->execute([Auth::id(),$id,$subtotal,$tax,$subtotal+$tax,$_POST['metodo_pago']??'Tarjeta',$sig]);$db->prepare("UPDATE usuarios SET tipo_usuario='premium' WHERE id=?")->execute([Auth::id()]);$_SESSION['user']['tipo_usuario']='premium';$db->commit();Flash::set('success','Membresía activada.');Auth::go('/mi-cuenta');} public function buyTicket(int $id):void{Auth::requireLogin();Csrf::verify();$qty=max(1,(int)($_POST['cantidad']??1));$db=Database::connection();$s=$db->prepare("SELECT * FROM eventos WHERE id=? AND estado=1");$s->execute([$id]);$e=$s->fetch();if(!$e)throw new \RuntimeException();$sub=(float)$e['precio']*$qty;$tax=round($sub*.07,2);$db->prepare("INSERT INTO compras(usuario_id,tipo,referencia_id,subtotal,itbms,total,metodo_pago,firma_digital) VALUES(?,'entrada',?,?,?,?,?,?)")->execute([Auth::id(),$id,$sub,$tax,$sub+$tax,$_POST['metodo_pago']??'Tarjeta',hash('sha256',Auth::id().'|'.$id.'|'.$qty.'|'.microtime(true))]);$db->prepare("INSERT INTO entradas(usuario_id,evento_id,cantidad,codigo_qr,total) VALUES(?,?,?,?,?)")->execute([Auth::id(),$id,$qty,strtoupper(bin2hex(random_bytes(6))),$sub+$tax]);Flash::set('success','Entradas compradas.');Auth::go('/mi-cuenta');}}
